import uvicorn
from fastapi import FastAPI, WebSocket, WebSocketDisconnect
from typing import List

app = FastAPI()

# In a real application, you might use a more sophisticated way to manage active connections.
# For this example, a simple list is sufficient.
active_connections: List[WebSocket] = []

@app.websocket("/ws")
async def websocket_endpoint(websocket: WebSocket):
    await websocket.accept()
    active_connections.append(websocket)
    try:
        while True:
            data = await websocket.receive_text()
            # Echo the message back to the sender
            await websocket.send_text(f"Message text was: {data}")
            # Or broadcast to all active connections (example)
            # for connection in active_connections:
            #     await connection.send_text(f"Client said: {data}")
    except WebSocketDisconnect:
        active_connections.remove(websocket)
        print("Client disconnected")

